package com.example.demoscalardl.functions;

import com.fasterxml.jackson.databind.JsonNode;
import com.scalar.db.api.Delete;
import com.scalar.db.api.Get;
import com.scalar.db.api.Put;
import com.scalar.db.api.Result;
import com.scalar.db.api.Scan;
import com.scalar.db.io.Key;
import com.scalar.dl.ledger.database.Database;
import com.scalar.dl.ledger.exception.ContractContextException;
import com.scalar.dl.ledger.function.JacksonBasedFunction;

/**
 * Generated by scalardl-skills (Function preset = UPSERT_RECORD).
 *
 * <p>Base name: PutAssetFunction, version: 1.0.0.
 *
 * <p>Behaviour: when the linked Contract executes, this Function writes (or overwrites) one row in
 * {@code ns_postgres.inventory}. The Function reads the same JSON the Contract received, so
 * {@code contractArgument} carries the fields used in the column mappings.
 *
 * <p><b>Why UPSERT_RECORD?</b> ScalarDL's Function {@code Database} exposes only
 * {@code get / scan / put / delete} today (no direct {@code Insert}/{@code Upsert} on the Function
 * side yet — that exposure is under consideration). The current {@code Database.put} forces an
 * implicit pre-read, so the storage-layer behaviour is upsert regardless. Naming this preset
 * {@code UPSERT_RECORD} matches the explicit upsert semantics ScalarDB is moving toward (its
 * {@code Put} class is being deprecated in favour of {@code Insert} / {@code Upsert} / {@code Update}).
 *
 * <p>Use this preset when:
 * <ul>
 *   <li>You're projecting a linked Contract's result into a ScalarDB row — typically pairs with
 *       single-asset Contracts ({@code PUT_ASSET}).</li>
 *   <li>You want to consume a value the Contract computed (e.g. new balance after a transfer, new
 *       quantity after a stock adjustment) — the {@code getContractContext} sample below is
 *       written for this case.</li>
 * </ul>
 *
 * <p><b>Common extensions</b> (ask Claude Code or edit by hand):
 * <ul>
 *   <li>Consume a Contract-computed value → uncomment and adapt the {@code getContractContext}
 *       sample below; use the retrieved value in the {@code Put.Builder} chain in place of the
 *       raw {@code contractArgument} field.</li>
 *   <li>Multi-record projection → if the linked Contract is {@code PUT_ASSETS}, switch to the
 *       {@code UPSERT_RECORDS} Function preset instead of editing this one.</li>
 *   <li>Validation → modify the precondition block.</li>
 * </ul>
 *
 * <p><b>Versioning (Function-specific):</b> unlike Contracts, Functions in ScalarDL CAN be
 * overwritten by a re-register call with the same id (Core's {@code FunctionManager.register}
 * does no existence check; {@code ScalarFunctionRegistry.bind} is a ScalarDB upsert). However,
 * this skill emits versioned class names ({@code <Base>FunctionV<M>_<m>_<p>}) for trace-ability,
 * debugging, and rollback. To overwrite this Function's bytecode in place, keep the same
 * {@code version} in the JSON and re-POST {@code /api/functions/register}. To deploy alongside
 * the previous version, bump the {@code version} and a fresh class id will be generated.
 */
public class PutAssetFunctionV1_0_0 extends JacksonBasedFunction {

    private static final String NAMESPACE = "ns_postgres";
    private static final String TABLE = "inventory";

    /**
     * @param database           mutable ScalarDB I/F. Supports {@code get/scan/put/delete} only.
     *                           {@code put} forces an implicit pre-read, so writes are upserts.
     * @param functionArgument   unsigned JSON the client sent for the Function. This skill's
     *                           generated Contracts ignore it; clients usually pass {@code "{}"}.
     * @param contractArgument   signed JSON the linked Contract received. The same domain JSON
     *                           the user POSTed. The default field source for the Put builder.
     * @param contractProperties JSON registered with the linked Contract at register time, or
     *                           {@code null}.
     * @return JSON returned to the client (joined with the Contract's return).
     */
    @Override
    public JsonNode invoke(
            Database<Get, Scan, Put, Delete, Result> database,
            JsonNode functionArgument,
            JsonNode contractArgument,
            JsonNode contractProperties) {

        // // The Contract typically calls setContext(...) with a value it just computed (e.g. the
        // // new balance after a transfer, the new stock quantity after an adjustment). Retrieve
        // // it here and use it in place of the raw contractArgument field. Example:
        // //
        // //   JsonNode ctx = getContractContext();
        // //   if (ctx == null) {
        // //       throw new ContractContextException("UPSERT_RECORD expected the Contract to setContext(...)");
        // //   }
        // //   int newQuantity = ctx.get("newQuantity").intValue();
        // //   // ... then in the Put.Builder chain below, replace
        // //   //     .intValue("quantity", contractArgument.get("delta").asInt())
        // //   //   with
        // //   //     .intValue("quantity", newQuantity)
        // //
        // // For multi-record projection (linked Contract is PUT_ASSETS), use the UPSERT_RECORDS
        // // Function preset instead of this one.

        if (!contractArgument.has("item")) {
            throw new ContractContextException("missing required field: item");
        }
        if (!contractArgument.has("qty")) {
            throw new ContractContextException("missing required field: qty");
        }
        if (!contractArgument.has("location")) {
            throw new ContractContextException("missing required field: location");
        }

        Key partitionKey = Key.newBuilder()
                .addText("location", contractArgument.get("location").asText())
                .build();

        Key clusteringKey = Key.newBuilder()
                .addText("item", contractArgument.get("item").asText())
                .build();

        Put put = Put.newBuilder()
                .namespace(NAMESPACE)
                .table(TABLE)
                .partitionKey(partitionKey)                .clusteringKey(clusteringKey)
                .intValue("qty", contractArgument.get("qty").asInt())
                .build();

        database.put(put);

        return getObjectMapper().createObjectNode()
                .put("status", "upserted")
                .put("table", NAMESPACE + "." + TABLE);
    }
}
